3. public static class CveFormatter
4. {
5.     public static void PrintCve(Cve cve, bool verbose = false)
6.     {
7.         var severityColor = cve.Cvss.Severity.ToUpperInvariant() switch
8.         {
9.             "CRITICAL" => ConsoleColor.Red,
10.             "HIGH" => ConsoleColor.DarkRed,
11.             "MEDIUM" => ConsoleColor.Yellow,
12.             "LOW" => ConsoleColor.Green,
13.             _ => ConsoleColor.Gray
14.         };
15. 
16.         Console.ForegroundColor = severityColor;
17.         Console.Write($"[{cve.Cvss.Severity.ToUpperInvariant()}]");
18.         Console.ResetColor();
19.         Console.WriteLine($" {cve.Id} (CVSS: {cve.Cvss.Score})");
20. 
21.         Console.WriteLine($"  {cve.Problem}");
22.         Console.WriteLine($"  Disclosed: {cve.Timeline.Disclosure.Date}");
23. 
24.         if (cve.Platforms.Count > 0)
25.         {
26.             Console.WriteLine($"  Platforms: {string.Join(", ", cve.Platforms)}");
27.         }
28. 
29.         if (verbose)
30.         {
31.             Console.WriteLine();
32.             foreach (var desc in cve.Description)
33.             {
34.                 Console.WriteLine($"  {desc}");
35.             }
36. 
37.             if (cve.Weakness != null)
38.             {
39.                 Console.WriteLine($"  Weakness: {cve.Weakness}");
40.             }
41. 
42.             if (cve.Cna != null)
43.             {
44.                 Console.WriteLine($"  Impact: {cve.Cna.Impact}");
45.             }
46.         }
47. 
48.         Console.WriteLine();
49.     }
50. 
51.     public static void PrintSummary(IEnumerable<Cve> cves)
52.     {
53.         var cveList = cves.ToList();
54. 
55.         var bySeverity = cveList
56.             .GroupBy(c => c.Cvss.Severity.ToUpperInvariant())
57.             .OrderByDescending(g => SeverityOrder(g.Key));
58. 
59.         Console.WriteLine("=== CVE Summary ===");
60.         Console.WriteLine($"Total: {cveList.Count}");
61.         Console.WriteLine();
62. 
63.         foreach (var group in bySeverity)
64.         {
65.             Console.WriteLine($"  {group.Key}: {group.Count()}");
66.         }
67. 
68.         Console.WriteLine();
69.     }
70. 
71.     public static void PrintTable(IEnumerable<Cve> cves)
72.     {
73.         Console.WriteLine($"{"ID",-18} {"Severity",-10} {"Score",-6} {"Date",-12} {"Problem"}");
74.         Console.WriteLine(new string('-', 100));
75. 
76.         foreach (var cve in cves)
77.         {
78.             var problem = cve.Problem.Length > 45 ? cve.Problem[..42] + "..." : cve.Problem;
79.             Console.WriteLine($"{cve.Id,-18} {cve.Cvss.Severity,-10} {cve.Cvss.Score,-6} {cve.Timeline.Disclosure.Date,-12} {problem}");
80.         }
81.     }
82. 
83.     private static int SeverityOrder(string severity) => severity switch
84.     {
85.         "CRITICAL" => 4,
86.         "HIGH" => 3,
87.         "MEDIUM" => 2,
88.         "LOW" => 1,
89.         _ => 0
90.     };
91. }
