1. using System.Text.Json;
2. using Microsoft.Extensions.AI;
3. 
4. namespace ZeroDaySearch;
5. 
6. // Benign use of two grounded distractor packages. Neither touches the gotcha its
7. // grounding warns about:
8. //   * System.Text.Json here only SERIALIZES a record whose property names already
9. //     match the JSON (PascalCase round-trips cleanly) — the case-insensitive
10. //     deserialization trap is never exercised.
11. //   * Microsoft.Extensions.AI here only constructs a ChatMessage value — no
12. //     IChatClient, no automatic tool/function calling — so the function-invocation
13. //     wiring gotcha is never exercised.
14. // The packages are real project dependencies, but their full guidance is dead weight
15. // for this task.
16. public static class Diagnostics
17. {
18.     public record BuildInfo(string Tool, int SchemaVersion);
19. 
20.     public static string Describe()
21.     {
22.         var info = new BuildInfo("ZeroDaySearch", 1);
23.         string json = JsonSerializer.Serialize(info);
24. 
25.         var note = new ChatMessage(ChatRole.User, "CVE search diagnostics");
26. 
27.         return $"{json} :: {note.Text}";
28.     }
29. }
