3. namespace ZeroDaySearch;
4. 
5. public class CveDataSource
6. {
7.     private const string ReleaseIndexUrl = "https://raw.githubusercontent.com/dotnet/core/refs/heads/release-index/release-notes/index.json";
8.     private readonly HttpClient _httpClient;
9. 
10.     public CveDataSource(HttpClient? httpClient = null)
11.     {
12.         _httpClient = httpClient ?? new HttpClient();
13.     }
14. 
15.     public async Task<ReleaseIndex> GetReleaseIndexAsync()
16.     {
17.         var json = await _httpClient.GetStringAsync(ReleaseIndexUrl);
18.         return JsonConvert.DeserializeObject<ReleaseIndex>(json)
19.             ?? throw new InvalidOperationException("Failed to deserialize release index");
20.     }
21. 
22.     public async Task<MajorReleaseIndex> GetMajorReleaseAsync(string url)
23.     {
24.         var json = await _httpClient.GetStringAsync(url);
25.         return JsonConvert.DeserializeObject<MajorReleaseIndex>(json)
26.             ?? throw new InvalidOperationException($"Failed to deserialize major release from {url}");
27.     }
28. 
29.     public async Task<CveRecords> GetCveRecordsAsync(string url)
30.     {
31.         var json = await _httpClient.GetStringAsync(url);
32.         return JsonConvert.DeserializeObject<CveRecords>(json)
33.             ?? throw new InvalidOperationException($"Failed to deserialize CVE records from {url}");
34.     }
35. 
36.     public async Task<List<CveRecords>> GetAllCveRecordsAsync(IEnumerable<string>? versions = null)
37.     {
38.         var releaseIndex = await GetReleaseIndexAsync();
39.         var allCveRecords = new List<CveRecords>();
40.         var seenCveUrls = new HashSet<string>();
41. 
42.         var releases = releaseIndex.Embedded.Releases
43.             .Where(r => versions == null || !versions.Any() || versions.Contains(r.Version));
44. 
45.         foreach (var release in releases)
46.         {
47.             try
48.             {
49.                 var majorRelease = await GetMajorReleaseAsync(release.Links.Self.Href);
50. 
51.                 foreach (var patch in majorRelease.Embedded.Patches.Where(p => p.Security && p.Links.CveJson != null))
52.                 {
53.                     var cveUrl = patch.Links.CveJson!.Href;
54.                     if (seenCveUrls.Add(cveUrl))
55.                     {
56.                         try
57.                         {
58.                             var cveRecords = await GetCveRecordsAsync(cveUrl);
59.                             allCveRecords.Add(cveRecords);
60.                         }
61.                         catch (HttpRequestException)
62.                         {
63.                             // Skip unavailable CVE files
64.                         }
65.                     }
66.                 }
67.             }
68.             catch (HttpRequestException)
69.             {
70.                 // Skip unavailable releases
71.             }
72.         }
73. 
74.         return allCveRecords;
75.     }
76. 
77.     public IEnumerable<Cve> FilterBySeverity(IEnumerable<CveRecords> records, string severity)
78.     {
79.         return records
80.             .SelectMany(r => r.Disclosures)
81.             .Where(c => c.Cvss.Severity.Equals(severity, StringComparison.OrdinalIgnoreCase))
82.             .DistinctBy(c => c.Id);
83.     }
84. 
85.     public IEnumerable<Cve> FilterByProduct(IEnumerable<CveRecords> records, string product)
86.     {
87.         var cveIds = records
88.             .SelectMany(r => r.Products)
89.             .Where(p => p.Name.Contains(product, StringComparison.OrdinalIgnoreCase))
90.             .Select(p => p.CveId)
91.             .ToHashSet();
92. 
93.         return records
94.             .SelectMany(r => r.Disclosures)
95.             .Where(c => cveIds.Contains(c.Id))
96.             .DistinctBy(c => c.Id);
97.     }
98. 
99.     public IEnumerable<Cve> FilterByDateRange(IEnumerable<CveRecords> records, DateOnly from, DateOnly to)
100.     {
101.         return records
102.             .SelectMany(r => r.Disclosures)
103.             .Where(c =>
104.             {
105.                 if (DateOnly.TryParse(c.Timeline.Disclosure.Date, out var date))
106.                 {
107.                     return date >= from && date <= to;
108.                 }
109.                 return false;
110.             })
111.             .DistinctBy(c => c.Id);
112.     }
113. 
114.     public IEnumerable<Cve> FilterByPlatform(IEnumerable<CveRecords> records, string platform)
115.     {
116.         return records
117.             .SelectMany(r => r.Disclosures)
118.             .Where(c => c.Platforms.Any(p =>
119.                 p.Equals(platform, StringComparison.OrdinalIgnoreCase) ||
120.                 p.Equals("all", StringComparison.OrdinalIgnoreCase)))
121.             .DistinctBy(c => c.Id);
122.     }
123. 
124.     public IEnumerable<Cve> GetLatestCves(IEnumerable<CveRecords> records, int count)
125.     {
126.         return records
127.             .SelectMany(r => r.Disclosures)
128.             .DistinctBy(c => c.Id)
129.             .OrderByDescending(c => c.Timeline.Disclosure.Date)
130.             .Take(count);
131.     }
132. 
133.     public IEnumerable<Cve> SearchByKeyword(IEnumerable<CveRecords> records, string keyword)
134.     {
135.         return records
136.             .SelectMany(r => r.Disclosures)
137.             .Where(c =>
138.                 c.Id.Contains(keyword, StringComparison.OrdinalIgnoreCase) ||
139.                 c.Problem.Contains(keyword, StringComparison.OrdinalIgnoreCase) ||
140.                 c.Description.Any(d => d.Contains(keyword, StringComparison.OrdinalIgnoreCase)))
141.             .DistinctBy(c => c.Id);
142.     }
143. }
